---- MODULE Bakery ----
EXTENDS Integers, Sequences
Max(S) == CHOOSE x \in S : \A y \in S : x >= y


CONSTANT N

(* Variables *)
VARIABLES num, flag

(* Type constraints *)
TypeOK == /\ num \in [1..N -> 0..N]
          /\ flag \in [1..N -> BOOLEAN]

(* Initial state: all processes have number 0 and are not choosing *)
Init == /\ num = [i \in 1..N |-> 0]
        /\ flag = [i \in 1..N |-> FALSE]

(* Helper: maximum number currently held by any process *)
maxNum == Max(Seq(num))

(* Helper: set of processes with a given number *)
procWithNum(n) == {i \in 1..N : num[i] = n}

(* Helper: set of processes with a number less than n *)
procWithNumLess(n) == {i \in 1..N : num[i] < n}

(* Helper: set of processes with a number greater than n *)
procWithNumGreater(n) == {i \in 1..N : num[i] > n}

(* Helper: set of processes with a number equal to n *)
procWithNumEqual(n) == {i \in 1..N : num[i] = n}

(* Helper: set of processes with a number less than or equal to n *)
procWithNumLessEqual(n) == {i \in 1..N : num[i] <= n}

(* Helper: set of processes with a number greater than or equal to n *)
procWithNumGreaterEqual(n) == {i \in 1..N : num[i] >= n}

(* Helper: set of processes with a number not equal to n *)
procWithNumNotEqual(n) == {i \in 1..N : num[i] # n}

(* Helper: set of processes with a number not equal to n and not zero *)
procWithNumNotEqualAndNotZero(n) == {i \in 1..N : num[i] # n /\ num[i] # 0}

